+import Yoga from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {kind: 'fixed'; size: number}
+	| {kind: 'fr'; fraction: number; min: number}
+	| {kind: 'auto'};
+
+type Placement = {start: number; end: number};
+
+const splitTracks = (template: string | undefined): string[] =>
+	(template?.match(/minmax\\([^)]*\\)|\\S+/g) ?? ['auto']);
+
+const parseTrack = (token: string): Track => {
+	if (token === 'auto') {
+		return {kind: 'auto'};
+	}
+
+	const fraction = /^(\\d*\\.?\\d+)fr$/.exec(token);
+	if (fraction) {
+		return {kind: 'fr', fraction: Number(fraction[1]), min: 0};
+	}
+
+	const minmax = /^minmax\\(\\s*(\\d*\\.?\\d+)\\s*,\\s*(\\d*\\.?\\d+)(fr)?\\s*\\)$/.exec(
+		token,
+	);
+	if (minmax) {
+		const min = Number(minmax[1]);
+		return minmax[3]
+			? {kind: 'fr', fraction: Number(minmax[2]), min}
+			: {kind: 'fixed', size: Number(minmax[2])};
+	}
+
+	const fixed = Number(token);
+	if (Number.isFinite(fixed) && fixed >= 0) {
+		return {kind: 'fixed', size: fixed};
+	}
+
+	throw new Error(`Invalid grid track size: ${token}`);
+};
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number') {
+		return {start: value - 1, end: value};
+	}
+
+	if (!value) {
+		return undefined;
+	}
+
+	const match = /^\\s*(\\d+)\\s*\\/\\s*(\\d+)\\s*$/.exec(value);
+	if (!match) {
+		throw new Error(`Invalid grid placement: ${value}`);
+	}
+
+	return {start: Number(match[1]) - 1, end: Number(match[2]) - 1};
+};
+
+const resolveTracks = (
+	tracks: Track[],
+	available: number | undefined,
+	intrinsic: number[],
+	gap: number,
+): number[] => {
+	const sizes = tracks.map((track, index) => {
+		if (track.kind === 'fixed') return track.size;
+		if (track.kind === 'auto') return intrinsic[index] ?? 0;
+		return track.min;
+	});
+
+	if (available === undefined) {
+		return sizes;
+	}
+
+	const remaining = available - gap * Math.max(tracks.length - 1, 0) - sizes.reduce((sum, size) => sum + size, 0);
+	const totalFraction = tracks.reduce(
+		(sum, track) => sum + (track.kind === 'fr' ? track.fraction : 0),
+		0,
+	);
+
+	if (remaining > 0 && totalFraction > 0) {
+		for (const [index, track] of tracks.entries()) {
+			if (track.kind === 'fr') sizes[index] += (remaining * track.fraction) / totalFraction;
+		}
+	}
+
+	return sizes;
+};
+
+const trackOffsets = (sizes: number[], gap: number): number[] => {
+	let offset = 0;
+	return sizes.map(size => {
+		const current = offset;
+		offset += size + gap;
+		return current;
+	});
+};
+
+const getGap = (node: DOMElement, direction: 'row' | 'column'): number =>
+	direction === 'row'
+		? node.style.rowGap ?? node.style.gap ?? 0
+		: node.style.columnGap ?? node.style.gap ?? 0;
+
+const gridChildren = (node: DOMElement): DOMElement[] =>
+	node.childNodes.filter(
+		(child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode),
+	);
+
+const placeGrid = (node: DOMElement): void => {
+	const yogaNode = node.yogaNode;
+	if (!yogaNode || node.style.display !== 'grid') return;
+
+	const children = gridChildren(node).filter(
+		child => child.yogaNode?.getDisplay() !== Yoga.DISPLAY_NONE,
+	);
+	const columns = splitTracks(node.style.gridTemplateColumns).map(parseTrack);
+	const rowTokens = node.style.gridTemplateRows ? splitTracks(node.style.gridTemplateRows) : [];
+	const explicitRows = rowTokens.map(parseTrack);
+	const placements = children.map(child => ({
+		column: parsePlacement(child.style.gridColumn),
+		row: parsePlacement(child.style.gridRow),
+	}));
+
+	let nextColumn = 0;
+	let nextRow = 0;
+	for (const placement of placements) {
+		if (!placement.column) {
+			placement.column = {start: nextColumn, end: nextColumn + 1};
+		}
+		if (!placement.row) {
+			placement.row = {start: nextRow, end: nextRow + 1};
+		}
+		nextColumn = placement.column.end;
+		if (nextColumn >= columns.length) {
+			nextColumn = 0;
+			nextRow += 1;
+		}
+	}
+
+	const rowCount = Math.max(
+		explicitRows.length,
+		...placements.map(placement => placement.row!.end),
+		1,
+	);
+	const rows = Array.from({length: rowCount}, (_, index) => explicitRows[index] ?? {kind: 'auto'});
+	const columnIntrinsic = Array<number>(columns.length).fill(0);
+	const rowIntrinsic = Array<number>(rows.length).fill(0);
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index];
+		const childYoga = child.yogaNode!;
+		if (placement.column!.end - placement.column!.start === 1) {
+			columnIntrinsic[placement.column!.start] = Math.max(columnIntrinsic[placement.column!.start], childYoga.getComputedWidth());
+		}
+		if (placement.row!.end - placement.row!.start === 1) {
+			rowIntrinsic[placement.row!.start] = Math.max(rowIntrinsic[placement.row!.start], childYoga.getComputedHeight());
+		}
+	}
+
+	const borderX = yogaNode.getComputedBorder(Yoga.EDGE_LEFT) + yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
+	const borderY = yogaNode.getComputedBorder(Yoga.EDGE_TOP) + yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const paddingX = yogaNode.getComputedPadding(Yoga.EDGE_LEFT) + yogaNode.getComputedPadding(Yoga.EDGE_RIGHT);
+	const paddingY = yogaNode.getComputedPadding(Yoga.EDGE_TOP) + yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM);
+	const columnGap = getGap(node, 'column');
+	const rowGap = getGap(node, 'row');
+	const contentWidth = yogaNode.getComputedWidth() - borderX - paddingX;
+	const contentHeight = node.style.height === undefined ? undefined : yogaNode.getComputedHeight() - borderY - paddingY;
+	const widths = resolveTracks(columns, contentWidth, columnIntrinsic, columnGap);
+	const heights = resolveTracks(rows, contentHeight, rowIntrinsic, rowGap);
+	const xOffsets = trackOffsets(widths, columnGap);
+	const yOffsets = trackOffsets(heights, rowGap);
+	const contentX = yogaNode.getComputedBorder(Yoga.EDGE_LEFT) + yogaNode.getComputedPadding(Yoga.EDGE_LEFT);
+	const contentY = yogaNode.getComputedBorder(Yoga.EDGE_TOP) + yogaNode.getComputedPadding(Yoga.EDGE_TOP);
+
+	if (node.style.height === undefined) {
+		yogaNode.setHeight(heights.reduce((sum, height) => sum + height, 0) + rowGap * Math.max(rows.length - 1, 0) + borderY + paddingY);
+	}
+
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index];
+		const column = placement.column!;
+		const row = placement.row!;
+		const width = widths.slice(column.start, column.end).reduce((sum, size) => sum + size, 0) + columnGap * Math.max(column.end - column.start - 1, 0);
+		const height = heights.slice(row.start, row.end).reduce((sum, size) => sum + size, 0) + rowGap * Math.max(row.end - row.start - 1, 0);
+		const childYoga = child.yogaNode!;
+		childYoga.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		childYoga.setPosition(Yoga.EDGE_LEFT, contentX + xOffsets[column.start]);
+		childYoga.setPosition(Yoga.EDGE_TOP, contentY + yOffsets[row.start]);
+		childYoga.setWidth(width);
+		childYoga.setHeight(height);
+	}
+};
+
+const applyGridLayout = (node: DOMElement): void => {
+	placeGrid(node);
+	for (const child of gridChildren(node)) applyGridLayout(child);
+};
+
+export default applyGridLayout;
